class JSZip{constructor(){this.files=[]}file(n,d){this.files.push({name:n,data:d});return this}async generateAsync(){const e=new TextEncoder(),parts=[],cd=[],crc=t=>{let c=-1;for(let i=0;i<t.length;i++){c^=t[i];for(let k=0;k<8;k++)c=c>>>1^((c&1)?0xedb88320:0)}return(c^-1)>>>0},put=(a,n,v)=>{for(let i=0;i<n;i++)a.push((v>>>(i*8))&255)};let off=0;for(const f of this.files){const data=new Uint8Array(await f.data.arrayBuffer()),name=e.encode(f.name),c=crc(data),head=[];put(head,4,0x04034b50);put(head,2,20);put(head,2,0);put(head,2,0);put(head,2,0);put(head,2,0);put(head,4,c);put(head,4,data.length);put(head,4,data.length);put(head,2,name.length);put(head,2,0);parts.push(...head,...name,...data);const cent=[];put(cent,4,0x02014b50);put(cent,2,20);put(cent,2,20);put(cent,2,0);put(cent,2,0);put(cent,2,0);put(cent,2,0);put(cent,4,c);put(cent,4,data.length);put(cent,4,data.length);put(cent,2,name.length);put(cent,2,0);put(cent,2,0);put(cent,2,0);put(cent,2,0);put(cent,4,0);put(cent,4,off);cd.push(...cent,...name);off=parts.length}const cdStart=parts.length;parts.push(...cd);const end=[];put(end,4,0x06054b50);put(end,2,0);put(end,2,0);put(end,2,this.files.length);put(end,2,this.files.length);put(end,4,cd.length);put(end,4,cdStart);put(end,2,0);parts.push(...end);return new Blob([new Uint8Array(parts)],{type:"application/zip"})}}
